import React, { useState, useEffect } from 'react';

function TestimonialCarousel() {
  const testimonials = [
    {
      id: 1,
      text: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed sit amet nulla auctor, vestibulum magna sed, convallis ex.',
      author: 'John Doe',
    },
    {
      id: 2,
      text: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed sit amet nulla auctor, vestibulum magna sed, convallis ex.',
      author: 'Jane Doe',
    },
    {
      id: 3,
      text: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed sit amet nulla auctor, vestibulum magna sed, convallis ex.',
      author: 'Bob Smith',
    },
  ];

  const [activeTestimonial, setActiveTestimonial] = useState(0);

  useEffect(() => {
    const intervalId = setInterval(() => {
      setActiveTestimonial((prevActiveTestimonial) => (prevActiveTestimonial + 1) % testimonials.length);
    }, 5000);

    return () => clearInterval(intervalId);
  }, [testimonials.length]);

  return (
    <section className="bg-white py-8 md:py-12 lg:py-16" aria-label="Testimonials Section">
      <div className="container mx-auto flex flex-col items-center justify-center gap-8 md:gap-12 lg:gap-16">
        <h2 className="text-2xl md:text-3xl lg:text-5xl font-bold text-zinc-900">
          What Our Customers Say
        </h2>
        <div className="flex flex-col items-center justify-center gap-4">
          {testimonials.map((testimonial, index) => (
            <div
              key={testimonial.id}
              className={`${
                activeTestimonial === index ? 'opacity-100' : 'opacity-50'
              } transition-opacity`}
            >
              <p className="text-lg md:text-xl lg:text-2xl text-zinc-600 text-center">
                {testimonial.text}
              </p>
              <p className="text-sm md:text-base lg:text-lg text-zinc-500 text-center">
                - {testimonial.author}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default TestimonialCarousel;

